class RabbitMQConfig:
    """Configuration for RabbitMQ connection with secure defaults."""

    def __init__(
        self,
        host: Optional[str] = None,
        port: Optional[int] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
        virtual_host: Optional[str] = None,
        use_ssl: bool = False,
        ssl_ca_certs: Optional[str] = None,
        heartbeat: int = 600,
        connection_attempts: int = 3,
        retry_delay: int = 5,
    ):
        self.host = host or os.environ.get('RABBITMQ_HOST', 'localhost')
        self.port = port or int(os.environ.get('RABBITMQ_PORT', '5672'))
        self.username = username or os.environ.get('RABBITMQ_USERNAME')
        self.password = password or os.environ.get('RABBITMQ_PASSWORD')
        self.virtual_host = virtual_host or os.environ.get('RABBITMQ_VHOST', '/')
        self.use_ssl = use_ssl or os.environ.get('RABBITMQ_USE_SSL', 'false').lower() == 'true'
        self.ssl_ca_certs = ssl_ca_certs or os.environ.get('RABBITMQ_SSL_CA_CERTS')
        self.heartbeat = heartbeat
        self.connection_attempts = connection_attempts
        self.retry_delay = retry_delay

        if not self.username or not self.password:
            raise ValueError(
                "RabbitMQ credentials must be provided via constructor arguments or "
                "environment variables RABBITMQ_USERNAME and RABBITMQ_PASSWORD. "
                "Do not use default 'guest' credentials in production."
            )

        if self.username == 'guest' and self.password == 'guest':
            logger.warning(
                "Using default 'guest/guest' credentials is insecure. "
                "Please configure strong credentials for production use."
            )

    def get_connection_parameters(self) -> pika.ConnectionParameters:
        """Build secure connection parameters."""
        credentials = pika.PlainCredentials(
            username=self.username,
            password=self.password
        )

        ssl_options = None
        if self.use_ssl:
            ssl_context = ssl.create_default_context()
            if self.ssl_ca_certs:
                ssl_context.load_verify_locations(self.ssl_ca_certs)
            ssl_options = pika.SSLOptions(ssl_context, self.host)

        return pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            ssl_options=ssl_options,
            heartbeat=self.heartbeat,
            connection_attempts=self.connection_attempts,
            retry_delay=self.retry_delay,
        )


class TaskPublisher:
    """Publishes task messages to RabbitMQ with secure connection handling."""

    def __init__(self, config: RabbitMQConfig, queue_name: str = 'task_queue'):
        self.config = config
        self.queue_name = queue_name
        self.connection = None
        self.channel = None

    def connect(self):
        """Establish connection to RabbitMQ."""
        try:
            params = self.config.get_connection_parameters()
            self.connection = pika.BlockingConnection(params)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            self.channel.confirm_deliveries()
            logger.info(f"Publisher connected to RabbitMQ at {self.config.host}:{self.config.port}")
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def publish_task(self, task_type: str, payload: dict, priority: int = 0) -> bool:
        """Publish a task message to the queue."""
        if not self.channel or self.channel.is_closed:
            self.connect()

        message = {
            'task_type': task_type,
            'payload': payload,
            'priority': priority,
            'timestamp': datetime.utcnow().isoformat(),
            'status': 'pending',
        }

        try:
            self.channel.basic_publish(
                exchange='',
                routing_key=self.queue_name,
                body=json.dumps(message),
                properties=pika.BasicProperties(
                    delivery_mode=2,  # persistent
                    content_type='application/json',
                    priority=priority,
                ),
            )
            logger.info(f"Published task: {task_type} with payload keys: {list(payload.keys())}")
            return True
        except pika.exceptions.UnroutableError:
            logger.error(f"Message was returned by the broker for task: {task_type}")
            return False
        except pika.exceptions.AMQPError as e:
            logger.error(f"Failed to publish task {task_type}: {e}")
            return False

    def close(self):
        """Close the connection gracefully."""
        try:
            if self.connection and not self.connection.is_closed:
                self.connection.close()
                logger.info("Publisher connection closed.")
        except Exception as e:
            logger.error(f"Error closing publisher connection: {e}")

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ with secure connection handling."""

    def __init__(
        self,
        config: RabbitMQConfig,
        queue_name: str = 'task_queue',
        prefetch_count: int = 1,
    ):
        self.config = config
        self.queue_name = queue_name
        self.prefetch_count = prefetch_count
        self.connection = None
        self.channel = None
        self.task_handlers: dict[str, Callable] = {}

    def register_handler(self, task_type: str, handler: Callable):
        """Register a handler function for a specific task type."""
        self.task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def connect(self):
        """Establish connection to RabbitMQ."""
        try:
            params = self.config.get_connection_parameters()
            self.connection = pika.BlockingConnection(params)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            self.channel.basic_qos(prefetch_count=self.prefetch_count)
            logger.info(f"Consumer connected to RabbitMQ at {self.config.host}:{self.config.port}")
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def _on_message(self, channel, method, properties, body):
        """Internal callback for processing received messages."""
        try:
            message = json.loads(body)
            task_type = message.get('task_type', 'unknown')
            payload = message.get('payload', {})
            timestamp = message.get('timestamp', '')

            logger.info(f"Received task: {task_type} (timestamp: {timestamp})")

            handler = self.task_handlers.get(task_type)
            if handler:
                try:
                    result = handler(payload)
                    logger.info(f"Task {task_type} completed successfully. Result: {result}")
                    channel.basic_ack(delivery_tag=method.delivery_tag)
                except Exception as e:
                    logger.error(f"Task {task_type} failed with error: {e}")
                    # Reject and requeue the message for retry
                    channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            else:
                logger.warning(f"No handler registered for task type: {task_type}")
                # Reject without requeue since no handler exists
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

        except json.JSONDecodeError as e:
            logger.error(f"Failed to decode message body: {e}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
        except Exception as e:
            logger.error(f"Unexpected error processing message: {e}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start_consuming(self):
        """Start consuming messages from the queue."""
        if not self.channel or self.channel.is_closed:
            self.connect()

        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self._on_message,
            auto_ack=False,
        )

        logger.info(f"Consumer started. Waiting for tasks on queue: {self.queue_name}")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user.")
            self.stop_consuming()

    def stop_consuming(self):
        """Stop consuming and close connection."""
        try:
            if self.channel and not self.channel.is_closed:
                self.channel.stop_consuming()
            if self.connection and not self.connection.is_closed:
                self.connection.close()
            logger.info("Consumer connection closed.")
        except Exception as e:
            logger.error(f"Error stopping consumer: {e}")


